sql:
SELECT COUNT(*) AS active_hpi_types
FROM hpi_types
WHERE is_active = 1;

SELECT hpi_flavor_name
FROM hpi_flavors
WHERE hpi_flavor_id = 1 AND created_at = '2023-05-01 10:00:00';

SELECT COUNT(*) AS total_active_hpi_records
FROM hpi
WHERE status = 'active';

SELECT is_active 
FROM hpi_types 
WHERE hpi_type_id = 1;

SELECT COUNT(DISTINCT hpi_id) AS total_hpi_entries
FROM access_logs
WHERE user_id = 1;

SELECT COUNT(hpi_type_id) AS active_hpi_type_count, 'Hive' AS frequency_name
FROM hpi_types
WHERE hpi_type_id = 1 AND is_active = 1;

SELECT hpi_type_name
FROM hpi_types
WHERE hpi_type_id > 0;

SELECT ROUND(AVG(data_size)) AS average_data_size
FROM hpi_data
WHERE hpi_id = 0;

SELECT MAX(processing_time) AS max_processing_time
FROM hpi
WHERE status = 'active';

SELECT COUNT(hpi_flavor_id) AS active_hpi_flavors
FROM hpi_flavors
WHERE is_active = 1;

SELECT COUNT(DISTINCT level_id) AS total_active_levels
FROM hpi
WHERE status = 'active';

SELECT hpi_type_name
FROM hpi_types
WHERE is_active = 1 AND description LIKE '%Hadoop%';

SELECT hpi_type_id 
FROM hpi 
WHERE place_name_id = (SELECT place_name_id FROM place_names WHERE place_name = 'node');

SELECT hpi_id
FROM hpi
WHERE processing_time = (SELECT MAX(processing_time) FROM hpi);

SELECT hpi_id
FROM hpi
WHERE status = 'active';
